# DE 2990.  Minden (Westf) - Hamm (Westf) Rbf Hvn
#
let hh = path("d3.de.e.1700");

with detail = 3,
     railway = :first :double :cat:ac15 :nopax
{
    with link = "line.de.2990" {
        track(:lor, hh[:lgr, :her.yk] >> 1ms >> 1md);
        track(:lor, hh[:her.yk, :swe - 0.5sw] >> 1ms >> 1md);
        track(:lor, hh[:swe - 0.5sw, :swe + 0.5sw] >> 1ms >> 1md);
        track(:lor, hh[:swe + 0.5sw, :her - 0.5sw] >> 1ms >> 1md);
    }

    # point.de.Herford  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:her.yh + 1md, :her.yh + 2.4km] >> 1ms >> 1md);
        line_label(:right:se, hh[:her.yh + 2.4km] >> 0.5ms >> 1md, "2990");
        track(:lor, hh[:her.yh + 2.4km, :ste - 0.5sw] >> 1ms >> 1md);
    }

    # point.de.Stedefreund  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:ste + 0.5sw, :brk - 0.5sw] >> 1ms >> 1md);
    }

    with link = "point.de.Brake-Bielefeld", railway = :station {
        track(hh[:brk - 0.5sw, :brk + 0.5sw] >> 1ms >> 1md);
        marker(:right :de.bbf :nopax, hh[:brk] >> 1ms >> 1.5md);
        slabel(:left :nopax, hh[:brk] >> 1ms >> 1.5md >> 1sh + (-0.5sw, 0dt),
            hbox(:left:base, "Brake ", span(:light, "(b Bielefeld)"))
        );
            
    }

    with link = "line.de.2990" {
        track(:lor, hh[:brk + 0.5sw, :tal - 0.3sw] >> 1ms >> 1md);
    }

    # point.de.Talbrücke-Brake  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:tal + 0.3sw, :eis - 0.3sw] >> 1ms >> 1md);
    }

    # point.de.Eissen-Bielefeld  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:eis + 0.3sw, :biv - 0.5sw] >> 1ms >> 1md);
    }

    with link = "point.de.Bielefeld-Hbf-Vorbahnhof", railway = :station {
        track(:nopax, hh[:biv - 0.5sw, :biv + 0.5sw] >> 1ms >> 1md);
        marker(:right :de.bft :nopax,
            hh[:biv] >> 0.5ms >> 1md, hh[:biv] >> 0.5ms
        );
        slabel(:left :nopax :xsmall,
            hh[:biv] >> 0.5ms >> 1md >> 1.1sh + (-1dt, 0dt),
            "B. Hbf Vorbahnhof"
        );
    }

    with link = "line.de.2990" {
        track(:lor, hh[:biv + 0.5sw, :bie.yl - 1md] >> 1ms >> 1md);
    }

    # point.de.Bielefeld-Hbf  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:bie + 230m + 2dl, :gne - 0.3sw] >> 1ms >> 1md);
    }

    # point.de.Gneisenaustraße-Bielefeld  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:gne + 0.3sw, :brg - 0.5sw] >> 1ms >> 1md);
    }

    with link = "point.de.Brackwede-Gbf", railway = :station {
        track(:nopax, hh[:brg - 0.5sw, :brg + 0.5sw] >> 1ms >> 1md);
        marker(:right :de.bft :nopax,
            hh[:brg] >> 1ms >> 1.5md, hh[:brg] >> 0.5ms
        );
        slabel(:left :nopax :xsmall,
            hh[:brg] >> 1ms >> 1.5md >> 1.6sh + (0dt, 1dt),
            "B. Gbf"
        );
    }

    with link = "line.de.2990" {
        track(:lor, hh[:brg + 0.5sw, :bra - 550m] >> 1ms >> 1md);
    }

    # point.de.Brackwede  de.1700

    with link = "line.de.2990" {
        track(:lor,
                hh[:bra.yp - 0.1dl, :bra.yp + 290m] >> 1md >> 2ms >> 1mt
            ..  hh[:bra.xp, :bra.xp + 0.1dl] >> 1ms >> 1md
        );
        track(:lor, hh[:bra.xp, :boc - 0.3sw] >> 1ms >> 1md);
    }

    # point.de.Bockschatz-Brackwede  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:boc + 0.3sw, :umm - 0.5sw] >> 1ms >> 1md);
    }

    # point.de.Ummeln  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:umm + 0.5sw, :isa - 0.5sw] >> 1ms >> 1md);
    }

    with link = "point.de.Isselhorst-Avenwedde-Anst", railway = :station {
        track(hh[:isa - 0.5sw, :iss + 0.5sw] >> 1ms >> 1md);
        marker(:right :de.awanst, hh[:isa] >> 1ms >> 1.5md);
        slabel(:left :xsmall,
            hh[:isa] >> 1ms >> 1.5md >> 1.55sh + (-0.3dt, 1.3dt),
            "I.-A. Anst"
        );
    }

    with link = "line.de.2990" {
        track(:ror:lor :casing,
                hh[:iss + 0.49sw, :iss + 0.5sw] >> 1ms >> 1md
            ..  hh[:iss.zs, :iss.zs + 0.1dl] << 1ms << 1md
        );
        track(:ror, hh[:iss.zs, :gut.yh - 950m] << 1ms << 1md);
        track(:ror :casing,
                hh[:gut.yh - 950m, :gut.yh - 400m] << 1ms << 1md
        );
    }

    # point.de.Gütersloh-Hbf  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:gut + 0.5sw, :hei - 0.5sw] << 1ms << 1md);
    }

    # point.de.Heidkamp de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:hei + 0.5sw, :ems - 0.5sw] << 1ms << 1md);
    }

    # point.de.Rheda-Ems  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:ems + 0.5sw, :rhe.yl - 500m] << 1ms << 1md);
    }

    # point.de.Rheda-Wiedenbrück de.1700

    with link = "line.de.2990" {
        track(:casing :ror,
                hh[:rhe.ym + 300m, :rhe.ym + 1km] << 1ms << 1md
        );
        track(:ror, hh[:rhe.ym + 1km, :bro] << 1ms << 1md);
    }

    # point.de.Rheda-Brock  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:bro, :men] << 1ms << 1md);
    }

    # point.de.Oelde-Menninghausen  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:men, :oel - 0.49sw] << 1ms << 1md);
    }

    # point.de.Oelde  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:oel + 0.49sw, :hoh] << 1ms << 1md);
    }

    # point.de.Oelde-Hohenhagen  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:hoh, :ang] << 1ms << 1md);
    }

    # point.de.Neubeckum-Angelbach  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:ang, :nbe.yw - 0.5seg] << 1ms << 1md);
    }

    # point.de.Neubeckum-Pbf  de.1700
    # point.de.Neubeckum-Gbf  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:nbg + 0.49sw, :vor - 0.49sw] << 1ms << 1md);
    }

    # point.de.Vorhelm  de.1700

    with link = "line.de.2990" {
        track(:ror, hh[:vor + 0.49sw, :ahg - 0.49sw] << 1ms << 1md);
    }

    with link = "point.de.Ahlen-Westf-Gbf", railway = :station {
        track(hh[:ahg - 0.5sw, :ahg + 0.5sw] << 1ms << 1md);
        marker(:left :de.bft :nopax, hh[:ahg] << 1ms << 1.5md, hh[:ahg]);
        slabel(:right :nopax :xsmall,
            hh[:ahg] << 1ms << 1.5md << 1sh + (1.5dt, 1.5dt),
            hbox(:left:base, "Ahlen ", span(:light, "(Westf)"), " Gbf")
        );
    }

    with link = "line.de.2990" {
        track(:ror, hh[:ahg + 0.49sw, :ahl - 0.49sw] << 1ms << 1md);
    }

    with link = "point.de.Ahlen-Westf-Notbahnsteig", railway = :station {
        track(hh[:ahl - 0.5sw, :ahl + 0.5sw] << 1ms << 1md);
        marker(:left :de.hp :nopax, hh[:ahl] << 1ms << 1.5md);
        slabel(:right :nopax, hh[:ahl] << 1ms << 1.5md << 1sh + (1.3dt, 1.5dt),
            hbox(:left:base, "A. ", span(:light, "(W.)"), " Notbahnsteig")
        )
    }

    with link = "line.de.2990" {
        track(:ror, hh[:ahl + 0.49sw, :ric.yn] << 1ms << 1md);
        with layer = -1 track(:ror:lor,
                hh[:ric.yn - 0.1dl, :ric.yn] << 1ms << 1md
            ..  hh[:ric.ys, :ric.ys + 0.1dl] >> 1ms >> 1md
        );
        track(:lor, hh[:ric.ys, :enn] >> 1ms >> 1md);
    }

    with link = "line.de.2990" {
        track(:ror, hh[:enn, :heh - 0.49sw] >> 1ms >> 1md);
    }

    # point.de.Heessen-Hp  de.1700

    with link = "line.de.2990" {
        track(:lor, hh[:heh + 0.49sw, :hee - 0.49sw] >> 1ms >> 1md);
    }

    with link = "point.de.Heessen", railway = :station {
        track(:pax, hh[:hee - 0.5sw, :hee + 0.5sw]);
        track(hh[:hee - 0.5sw, :hee + 0.5sw] >> 1ms >> 1md);
        marker(:right :de.bbf, hh[:hee] >> 1ms >> 1.5md);
        slabel(:right, hh[:hee] << 0.5md + (1.3dt, 1.5dt), "Heessen");
    }

    with link = "line.de.2990" {
        with layer = -1 track(:ror, hh[:hee + 0.49sw, :hee.yh] >> 1ms >> 1md);
        with layer = -1 track(:single :ror:lor,
                hh[:hee.yh, :ham.yf] >> 0.5md >> 1ms >> 0.5mt
        );
        with layer = -1 track(:single :lor,
                hh[:hee.yh - 0.1dl, :hee.yh] >> 1ms >> 1.5md << 0.5mt
            ..  hh[:ham.yf, :ham.yf + 0.1dl] >> 1.5md >> 3ms >> 1.5mt
        );
